package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testIsCommentingEnabledWhenCommentStartIsNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        setCommentStart(format, null);
        assertFalse(format.isCommentingEnabled());
    }

    @Test
    void testIsCommentingEnabledWhenCommentStartIsChar() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        setCommentStart(format, '#');
        assertTrue(format.isCommentingEnabled());
    }

    @Test
    void testIsCommentingEnabledWhenCommentStartIsCharacterObject() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        setCommentStart(format, Character.valueOf('!'));
        assertTrue(format.isCommentingEnabled());
    }

    private void setCommentStart(CSVFormat format, Character commentStart) throws Exception {
        Field field = CSVFormat.class.getDeclaredField("commentStart");
        field.setAccessible(true);

        // CSVFormat fields are final, so we need to remove final modifier via reflection if necessary
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(field, field.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

        field.set(format, commentStart);
    }
}
